// ★ 動画ファイルを文字起こして学習データに追加
async function handleLearnVideo(e, mode) {
  const file = e.target.files[0];
  if (!file) return;
  const statusEl = mode === 'add' ? DOM.learnStatus : DOM.editLearnStatus;
  statusEl.style.color = '';
  statusEl.style.whiteSpace = '';

  // ファイルサイズ事前チェック（200MB超はアップロード不可）
  const MAX_VIDEO_MB = 200;
  const fileMB = Math.round(file.size / 1024 / 1024);
  if (file.size > MAX_VIDEO_MB * 1024 * 1024) {
    statusEl.textContent = `❌ ファイルが大きすぎます（${fileMB}MB）\nサーバーへのアップロード上限は200MBです\n💡 YouTube URLを「YouTube」ボタンで入力するか、動画をmp3に変換してから「音声」ボタンをお試しください`;
    statusEl.style.color = 'var(--accent-red)';
    statusEl.style.whiteSpace = 'pre-line';
    e.target.value = '';
    return;
  }

  statusEl.textContent = `${file.name}（${fileMB}MB）を文字起こし中...（時間がかかります）`;
  try {
    const formData = new FormData();
    formData.append('video', file);
    const res = await fetch('/api/learn/transcribe-video', { method: 'POST', body: formData });
    let data; try { data = await res.json(); } catch { data = {}; }
    if (!res.ok) throw new Error(data.error || (res.status === 504 || res.status === 502 ? 'サーバーがタイムアウトしました。ファイルが大きすぎるか処理時間が超過した可能性があります。' : `サーバーエラー（${res.status}）が発生しました。`));
    const listKey = mode === 'add' ? 'addLearnFiles' : 'editLearnFiles';
    State[listKey].push({ name: `🎬 ${file.name}`, type: 'text', content: data.text });
    renderLearnDataList(mode);
    statusEl.style.color = ''; statusEl.textContent = `✓ 文字起こし完了（${data.text.length}文字）`;
    setTimeout(() => { statusEl.textContent = ''; }, 3000);
  } catch (e) {
    const friendlyMsg = translateLearnError(e.message, '音声文字起こし');
    statusEl.textContent = friendlyMsg;
    statusEl.style.color = 'var(--accent-red)';
    statusEl.style.whiteSpace = 'pre-line';
  }
  e.target.value = '';
}

// ★ URL・SNS・YouTube から学習データを取得
async function fetchLearnUrl(mode, type) {
  const inputId = mode === 'add' ? 'learnUrlInput' : 'editLearnUrlInput';
  const inputEl = $(inputId);
  const statusEl = mode === 'add' ? DOM.learnStatus : DOM.editLearnStatus;
  const url = inputEl.value.trim();
  if (!url) { showToast('URLを入力してください', 'error'); return; }

  const endpoint = type === 'youtube' ? '/api/learn/fetch-youtube' : '/api/learn/fetch-url';
  statusEl.textContent = type === 'youtube' ? '取得中...（字幕検索→音声変換の順に試みます）' : '取得中...';
  statusEl.style.color = '';
  statusEl.style.whiteSpace = '';

  try {
    const res = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ url })
    });
    let data; try { data = await res.json(); } catch { data = {}; }
    if (!res.ok) throw new Error(data.error || (res.status === 504 || res.status === 502 ? 'サーバーがタイムアウトしました。しばらく待ってから再試行してください。' : `サーバーエラー（${res.status}）が発生しました。`));

    const listKey = mode === 'add' ? 'addLearnFiles' : 'editLearnFiles';
    const icon = type === 'youtube' ? '▶' : '🌐';
    const label = `${icon} ${url.length > 40 ? url.slice(0, 40) + '…' : url}`;
    State[listKey].push({ name: label, type: 'text', content: data.text });
    renderLearnDataList(mode);
    statusEl.style.color = ''; statusEl.textContent = `✓ 取得完了（${data.text.length}文字）`;
    inputEl.value = '';
    setTimeout(() => { statusEl.textContent = ''; }, 3000);
  } catch (e) {
    const friendlyMsg = translateLearnError(e.message, type === 'youtube' ? 'YouTube' : 'Web');
    statusEl.textContent = friendlyMsg;
    statusEl.style.color = 'var(--accent-red)';
    statusEl.style.whiteSpace = 'pre-line';
  }
}

