function escapeHtml(text) { const d = document.createElement('div'); d.textContent = text; return d.innerHTML; }

// ===== フィードバックモーダル制御 =====
const FeedbackState = { members: [], currentIndex: 0, rating: null };

function startFeedbackFlow() {
  if (!State.sessionId || !State.members || State.members.length === 0) return;
  // ログインユーザーのみフィードバックを表示
  if (!State.currentUser) return;
  FeedbackState.members = State.members.filter(m => m.id !== 'facilitator');
  FeedbackState.currentIndex = 0;
  FeedbackState.rating = null;
  showFeedbackModal();
}

function showFeedbackModal() {
  const members = FeedbackState.members;
  const idx = FeedbackState.currentIndex;
  if (idx >= members.length) {
    closeFeedbackModal();
    return;
  }
  const persona = members[idx];

  // アイコン行を更新
  DOM.feedbackPersonaIcons.innerHTML = members.map((m, i) => {
    const initial = m.name ? m.name[0] : '?';
    const cls = i === idx ? 'active' : 'inactive';
    return `<div class="feedback-persona-icon ${cls}">${initial}</div>`;
  }).join('') + `<span style="font-size:12px;color:var(--text-muted);margin-left:6px;">ペルソナ ${idx + 1} / ${members.length}</span>`;

  // タイトル更新
  DOM.feedbackModalTitle.textContent = `${persona.name}へのフィードバック`;

  // フォームリセット
  DOM.feedbackBtnGood.className = 'feedback-rating-btn';
  DOM.feedbackBtnBad.className = 'feedback-rating-btn';
  DOM.feedbackComment.value = '';
  DOM.feedbackLearnCheck.checked = false;
  FeedbackState.rating = null;

  DOM.feedbackModal.classList.remove('hidden');
}

function selectFeedbackRating(isGood) {
  FeedbackState.rating = isGood;
  DOM.feedbackBtnGood.className = 'feedback-rating-btn' + (isGood ? ' selected-good' : '');
  DOM.feedbackBtnBad.className = 'feedback-rating-btn' + (!isGood ? ' selected-bad' : '');
}

async function submitFeedback() {
  const members = FeedbackState.members;
  const idx = FeedbackState.currentIndex;
  const persona = members[idx];
  if (FeedbackState.rating === null) {
    showToast('「良かった」か「良くなかった」を選んでください', 'error');
    return;
  }
  DOM.feedbackSubmitBtn.disabled = true;
  try {
    const data = await API.post(`/api/personas/${persona.id}/feedback`, {
      rating: FeedbackState.rating,
      correct_response: DOM.feedbackComment.value.trim(),
      add_to_learn: DOM.feedbackLearnCheck.checked,
      session_id: State.sessionId
    });
    if (data.level_up) {
      delete State.growthCache[persona.id];
      showToast(`✨ ${persona.name} が Lv${data.new_level}「${data.level_name}」に上がりました！`, 'success');
    }
    FeedbackState.currentIndex++;
    if (FeedbackState.currentIndex >= members.length) {
      closeFeedbackModal();
      if (!data.level_up) {
        showToast('フィードバックを送信しました。ありがとうございます！', 'success');
      }
    } else {
      showFeedbackModal();
    }
  } catch (e) {
    showToast(translateApiError(e.message, 'フィードバックの送信'), 'error');
  } finally {
    DOM.feedbackSubmitBtn.disabled = false;
  }
}

function skipFeedback() {
  FeedbackState.currentIndex++;
  if (FeedbackState.currentIndex >= FeedbackState.members.length) {
    closeFeedbackModal();
  } else {
    showFeedbackModal();
  }
}

function closeFeedbackModal() {
  if (DOM.feedbackModal) DOM.feedbackModal.classList.add('hidden');
}

// ★ 学習データ取得エラーをユーザー向けに翻訳
function translateLearnError(errorMsg, type) {
  if (!errorMsg) return '❌ 不明なエラーが発生しました\nページを再読み込みして再試行してください';
  const msg = errorMsg.toLowerCase();

  // ── 通信・接続 ──
  if (msg.includes('failed to fetch') || msg.includes('networkerror') || msg.includes('network request failed')) {
    return '❌ サーバーに接続できませんでした\nインターネット接続を確認して再試行してください';
  }
  if (msg.includes('タイムアウトしました') || msg.includes('timeout') || msg.includes('timed out')) {
    return '⚠️ 処理がタイムアウトしました\n大きなファイルや長い動画は時間がかかります\n💡 YouTubeの場合はURLを「YouTube」ボタンで入力するか\n　 ファイルを短く分割してからアップロードしてください';
  }
  if (msg.includes('サーバーエラー') || msg.includes('502') || msg.includes('504') || msg.includes('bad gateway') || msg.includes('gateway timeout')) {
    return '⚠️ サーバーで一時的なエラーが発生しました\nしばらく待ってから再試行してください\n💡 大きなファイルは処理に時間がかかるため、繰り返し失敗する場合は\n　 ファイルを短く分割するか YouTube URLをお試しください';
  }
  if (msg.includes('maximum content size') || msg.includes('413') || msg.includes('request entity too large')) {
    return '❌ ファイルが大きすぎてサーバーに届きませんでした\nYouTube URLを「YouTube」ボタンで入力するか\n動画をmp3に変換してからアップロードしてください';
  }

  // ── YouTube フォーマット・取得失敗 ──
  if (msg.includes('requested format is not available') || msg.includes('use --list-formats') || msg.includes('no video formats found')) {
    return '❌ この動画のフォーマットを取得できませんでした\n動画ファイルをローカルにダウンロードして「動画」ボタンでアップロードするか\n字幕付き動画をお試しください';
  }
  if (msg.includes('unable to download') || msg.includes('download failed') || msg.includes('ダウンロードに失敗')) {
    return '❌ 動画のダウンロードに失敗しました\n時間をおいて再試行するか、別の動画をお試しください';
  }

  // ── YouTube アクセス制限 ──
  if (msg.includes('sign in to confirm') || msg.includes('not a bot') || msg.includes('confirm you')) {
    return '❌ YouTubeのBot検知によりブロックされました\n少し時間をおいてから再試行してください\n💡 字幕付き動画では「YouTube」ボタンで取得できることがあります';
  }
  if (msg.includes('age') && (msg.includes('restrict') || msg.includes('limit'))) {
    return '❌ この動画は年齢制限のためダウンロードできません\n別の動画をお試しください';
  }
  if (msg.includes('members only') || msg.includes('member-only') || msg.includes('join this channel')) {
    return '❌ この動画はチャンネルメンバー限定です\n公開動画をお試しください';
  }
  if (msg.includes('copyright') || msg.includes('unavailable in your country') || msg.includes('not available in your region')) {
    return '❌ この動画は著作権または地域制限により取得できません\n別の動画をお試しください';
  }
  if (msg.includes('video unavailable') || msg.includes('private video') || msg.includes('has been removed')) {
    return '❌ この動画は非公開・削除済み、または視聴できない状態です';
  }
  if (msg.includes('subtitles are disabled') || msg.includes('no transcripts')) {
    return '⚠️ この動画は字幕が無効のため取得できませんでした\n「YouTube」ボタンで音声から文字起こしを試みます（自動実行中...）';
  }
  if (msg.includes('could not retrieve a transcript')) {
    return '⚠️ 字幕データが見つかりませんでした\n音声文字起こしを試みています...';
  }
  if (msg.includes('url') && (msg.includes('invalid') || msg.includes('not valid') || msg.includes('正しくありません'))) {
    return '❌ URLの形式が正しくありません\nYouTubeのURLを貼り付けてください（例：https://www.youtube.com/watch?v=...）';
  }

  // ── 音声変換・処理 ──
  if (msg.includes('ffmpeg') || msg.includes('no such file or directory')) {
    return '❌ 動画処理ツール（ffmpeg）が見つかりません\nサーバーの設定に問題がある可能性があります\nYouTube URLをお試しください';
  }
  if (msg.includes('変換に失敗') || msg.includes('conversion failed') || msg.includes('音声抽出失敗')) {
    return '❌ 音声の変換に失敗しました\n動画に音声トラックがないか、対応していない形式の可能性があります\n別のファイルをお試しください';
  }
  if (msg.includes('could not be decoded') || msg.includes('invalid file format') || msg.includes('音声ファイルが空')) {
    return '❌ 音声ファイルの形式を認識できませんでした\nmp3またはmp4形式のファイルをお試しください';
  }
  if (msg.includes('音声トラックがない') || msg.includes('no audio') || msg.includes('no stream')) {
    return '❌ このファイルに音声が含まれていません\n音声付きの動画・音声ファイルをお試しください';
  }

  // ── OpenAI API ──
  if (msg.includes('insufficient_quota') || msg.includes('you exceeded your current quota')) {
    return '❌ AIサービスの利用上限に達しました\n管理者にお問い合わせください';
  }
  if (msg.includes('rate limit') || msg.includes('rate_limit') || msg.includes('too many requests') || msg.includes('429')) {
    return '⚠️ AIサービスへのリクエストが集中しています\n1〜2分待ってから再試行してください';
  }
  if (msg.includes('error code: 400') || msg.includes('bad request')) {
    return '❌ 音声データの送信に失敗しました\nファイルが破損している可能性があります\n別のファイルをお試しください';
  }
  if (msg.includes('error code: 500') || msg.includes('internal server error') || msg.includes('service unavailable')) {
    return '⚠️ AIサービスが一時的に利用できません\nしばらく待ってから再試行してください';
  }

  // ── PDF ──
  if (msg.includes('スキャン') || (msg.includes('pdf') && msg.includes('text'))) {
    return '❌ このPDFはスキャン画像のためテキスト抽出できません\n手動でテキストを入力してください';
  }

  // ── デフォルト ──
  return `❌ ${type || ''}エラーが発生しました\n詳細: ${errorMsg.slice(0, 120)}`;
}

// ★ API全般エラーをユーザー向けに翻訳（会議・ペルソナ・認証など）
function translateApiError(errorMsg, context) {
  if (!errorMsg) return `${context || ''}でエラーが発生しました。再試行してください。`;
  const msg = errorMsg.toLowerCase();
  if (msg.includes('failed to fetch') || msg.includes('networkerror')) {
    return 'サーバーに接続できませんでした。インターネット接続を確認してください。';
  }
  if (msg.includes('overloaded') || msg.includes('529') || msg.includes('503')) {
    return 'AIサーバーが混雑しています。しばらく待ってから再試行してください。';
  }
  if (msg.includes('rate limit') || msg.includes('429') || msg.includes('too many')) {
    return 'リクエストが集中しています。1〜2分待ってから再試行してください。';
  }
  if (msg.includes('insufficient_quota') || msg.includes('quota')) {
    return 'AIサービスの利用上限に達しました。管理者にお問い合わせください。';
  }
  // Anthropic API認証エラー（"error code: 401" の形式）
  if (msg.includes('authentication_error') || msg.includes('invalid x-api-key') || msg.includes('invalid api key')) {
    return '⚠️ AIサービスの認証に失敗しました。APIキーを確認してください。';
  }
  // サーバーログインエラー（Flaskが返す "ログインが必要です" のみ）
  if (msg.includes('ログインが必要') || msg === 'unauthorized') {
    return 'ログインが必要です。右上の「ログイン」からログインしてください。';
  }
  // 汎用401（ただしAnthropicエラーは上で捕捉済みのため、ここに来るのはFlask 401のみ）
  if (msg.includes('unauthorized')) {
    return 'ログインが必要です。右上の「ログイン」からログインしてください。';
  }
  if (msg.includes('not found') || msg.includes('404')) {
    return 'データが見つかりませんでした。ページを再読み込みしてください。';
  }
  if (msg.includes('timeout')) {
    return '処理がタイムアウトしました。しばらく待ってから再試行してください。';
  }
  return `${context || ''}でエラーが発生しました: ${errorMsg.slice(0, 100)}`;
}


// ===== 認証機能 =====

async function checkAuthStatus() {
  try {
    const data = await API.get('/api/auth/me');
    if (data.user) {
      State.currentUser = data.user;
      renderAuthArea();
      // 支払い完了後のリダイレクト処理
      const params = new URLSearchParams(window.location.search);
      if (params.get('payment') === 'success') {
        const sessionId = params.get('session_id');
        history.replaceState(null, '', window.location.pathname);
        if (sessionId) {
          await verifyAndApplyPayment(sessionId);
        } else {
          // session_id がない場合は従来の polling fallback
          await refreshPaymentStatus();
          showToast('お支払いが完了しました！', 'success');
        }
      } else if (params.get('payment') === 'cancel') {
        showToast('お支払いがキャンセルされました。', 'info');
        history.replaceState(null, '', window.location.pathname);
      }
    } else {
      renderAuthArea();
    }
  } catch (e) {
    renderAuthArea();
  }
}

async function refreshPaymentStatus() {
  if (!State.currentUser) return;
  try {
    const data = await API.get('/api/payment/status');
    State.paymentStatus = data;
    State.currentUser.plan = data.plan;
    State.currentUser.credits = data.credits;
    State.currentUser.plan_expires_at = data.plan_expires_at;
    State.currentUser.monthly_meeting_count = data.monthly_meeting_count;
    renderAuthArea();
  } catch (e) {
    // ログインしていない場合などは無視
  }
}

async function verifyAndApplyPayment(sessionId) {
  // Stripe セッションを直接検証してプランを即時反映（webhook 到着前でも動作）
  showToast('お支払いを確認中...', 'info');
  let retries = 0;
  const maxRetries = 6;
  const delays = [1000, 2000, 3000, 4000, 5000, 8000];

  while (retries < maxRetries) {
    await new Promise(r => setTimeout(r, delays[retries] || 3000));
    try {
      const data = await API.post('/api/payment/verify-session', { session_id: sessionId });
      if (data.verified && data.status) {
        State.currentUser.plan = data.status.plan;
        State.currentUser.credits = data.status.credits;
        State.currentUser.plan_expires_at = data.status.plan_expires_at;
        State.currentUser.monthly_meeting_count = data.status.monthly_meeting_count;
        renderAuthArea();
        const planLabels = { standard: 'スタンダード（50チケット）', pro: 'プロ（月間無制限）' };
        const label = planLabels[data.status.plan] || data.status.plan;
        showToast(`お支払い完了！${label}に更新されました。`, 'success');
        return;
      }
      if (data.verified === false) {
        // 未完了状態 → リトライ
        retries++;
        continue;
      }
    } catch (e) {
      retries++;
      continue;
    }
    retries++;
  }
  // タイムアウト: webhook 処理を待って status を更新
  await refreshPaymentStatus();
  showToast('お支払いは完了していますが反映に時間がかかっています。しばらくお待ちください。', 'info');
}

function renderAuthArea() {
  const area = $('authArea');
  if (!area) return;
  if (State.currentUser) {
    const u = State.currentUser;
    const plan = u.plan || 'free';
    const planLabels = { free: '無料', standard: 'スタンダード', pro: 'PRO' };
    const planLabel = planLabels[plan] || plan;
    const creditsHtml = (plan === 'standard')
      ? `<span class="credits-badge">${u.credits || 0}回</span>`
      : '';
    const upgradeHtml = (plan === 'free')
      ? `<button class="btn btn-upgrade" onclick="openPricingModal()">アップグレード</button>`
      : '';
    area.innerHTML = `
      <div class="user-badge">
        <span>👤</span>
        <span class="user-name">${escapeHtml(u.name || u.email)}</span>
        <span class="plan-badge ${plan}">${planLabel}</span>
        ${creditsHtml}
      </div>
      ${upgradeHtml}
      <button class="btn" id="logoutBtn" onclick="logout()">ログアウト</button>
    `;
  } else {
    area.innerHTML = `<button class="btn" id="loginBtnHeader" onclick="openAuthModal()">🔑 ログイン</button>`;
  }
}

function openAuthModal() {
  $('authModalOverlay').classList.remove('hidden');
  showLoginPanel();
}

function closeAuthModal() {
  $('authModalOverlay').classList.add('hidden');
  $('loginError').textContent = '';
  $('registerError').textContent = '';
}

function showLoginPanel() {
  $('loginPanel').classList.remove('hidden');
  $('registerPanel').classList.add('hidden');
}

function showRegisterPanel() {
  $('loginPanel').classList.add('hidden');
  $('registerPanel').classList.remove('hidden');
}

async function submitLogin() {
  const email = $('loginEmail').value.trim();
  const password = $('loginPassword').value.trim();
  const errEl = $('loginError');
  if (!email || !password) { errEl.textContent = 'メールアドレスとパスワードを入力してください'; return; }
  try {
    const btn = $('loginSubmitBtn');
    btn.textContent = 'ログイン中...'; btn.disabled = true;
    const data = await API.post('/api/auth/login', { email, password });
    State.currentUser = data.user;
    renderAuthArea();
    closeAuthModal();
    showToast(`${data.user.name || data.user.email} でログインしました`, 'success');
    // ペルソナを再読み込み（ユーザー固有のペルソナを反映）
    await reloadPersonas();
    if (!localStorage.getItem('guide_shown')) showGuideModal();
  } catch (e) {
    $('loginError').textContent = translateApiError(e.message, 'ログイン');
  } finally {
    const btn = $('loginSubmitBtn');
    if (btn) { btn.textContent = 'ログイン'; btn.disabled = false; }
  }
}

async function submitRegister() {
  const name = $('registerName').value.trim();
  const email = $('registerEmail').value.trim();
  const password = $('registerPassword').value.trim();
  const errEl = $('registerError');
  if (!email || !password) { errEl.textContent = 'メールアドレスとパスワードを入力してください'; return; }
  if (password.length < 6) { errEl.textContent = 'パスワードは6文字以上にしてください'; return; }
  try {
    const btn = $('registerSubmitBtn');
    btn.textContent = '登録中...'; btn.disabled = true;
    const data = await API.post('/api/auth/register', { email, password, name });
    State.currentUser = data.user;
    renderAuthArea();
    closeAuthModal();
    showToast(`登録完了！${data.user.name || data.user.email} でログインしました`, 'success');
    await reloadPersonas();
    if (!localStorage.getItem('guide_shown')) showGuideModal();
  } catch (e) {
    $('registerError').textContent = translateApiError(e.message, '登録');
  } finally {
    const btn = $('registerSubmitBtn');
    if (btn) { btn.textContent = '登録する'; btn.disabled = false; }
  }
}

async function logout() {
  try {
    await API.post('/api/auth/logout', {});
    State.currentUser = null;
    renderAuthArea();
    showToast('ログアウトしました', 'success');
    await reloadPersonas();
  } catch (e) { showToast(translateApiError(e.message, 'ログアウト'), 'error'); }
}

async function reloadPersonas() {
  try {
    const data = await API.get('/api/personas/members');
    State.members = data.members;
    State.members.forEach(m => {
      if (m.avatar && m.avatar.startsWith('data:')) {
        State.avatarImages[m.id] = m.avatar;
      } else if (DEFAULT_AVATARS[m.id]) {
        State.avatarImages[m.id] = DEFAULT_AVATARS[m.id];
      }
    });
    // ファシリテータのアバター更新
    if (data.facilitator?.avatar?.startsWith('data:')) {
      State.avatarImages['facilitator'] = data.facilitator.avatar;
    }
    renderMemberList();
  } catch (e) { showToast(translateApiError(e.message, 'ペルソナの再読み込み'), 'error'); }
}

// ===== はじめ方ガイド =====
function showGuideModal() {
  $('guideModal').classList.remove('hidden');
}
function closeGuideModal() {
  $('guideModal').classList.add('hidden');
  localStorage.setItem('guide_shown', '1');
}

// ===== 料金プランモーダル =====

function openPricingModal(reason) {
  const overlay = $('pricingModalOverlay');
  if (!overlay) return;
  const planEl = $('pricingCurrentPlan');
  if (planEl && State.currentUser) {
    const plan = State.currentUser.plan || 'free';
    const credits = State.currentUser.credits || 0;
    const monthly = State.currentUser.monthly_meeting_count || 0;
    let msg = '';
    if (reason) msg = `<div style="color:#FCA5A5;margin-bottom:6px;font-size:12px;">⚠️ ${escapeHtml(reason)}</div>`;
    if (plan === 'free') {
      msg += `現在のプラン: <b>無料</b> · 今月 ${monthly}/5 回使用済み`;
    } else if (plan === 'standard') {
      msg += `現在のプラン: <b>スタンダード</b> · 残り ${credits} チケット`;
    } else if (plan === 'pro') {
      const exp = State.currentUser.plan_expires_at
        ? new Date(State.currentUser.plan_expires_at).toLocaleDateString('ja-JP')
        : '—';
      msg += `現在のプラン: <b>PRO</b> · 有効期限: ${exp}`;
    }
    planEl.innerHTML = msg;
    planEl.classList.remove('hidden');
  }
  // ボタン状態更新
  const plan = State.currentUser?.plan || 'free';
  const stdBtn = $('buyStandardBtn');
  const proBtn = $('buyProBtn');
  if (stdBtn) stdBtn.disabled = false;
  if (proBtn) proBtn.disabled = (plan === 'pro');
  overlay.classList.remove('hidden');
}

function closePricingModal() {
  const overlay = $('pricingModalOverlay');
  if (overlay) overlay.classList.add('hidden');
}

async function purchasePlan(type) {
  if (!State.currentUser) {
    closePricingModal();
    openAuthModal();
    return;
  }
  const btn = type === 'standard' ? $('buyStandardBtn') : $('buyProBtn');
  if (btn) { btn.disabled = true; btn.textContent = '処理中...'; }
  try {
    const data = await API.post('/api/payment/checkout', { type });
    if (data.checkout_url) {
      window.location.href = data.checkout_url;
    }
  } catch (e) {
    showToast(`決済エラー: ${e.message}`, 'error');
    if (btn) { btn.disabled = false; btn.textContent = type === 'standard' ? 'チケットを購入' : 'プロプランに登録'; }
  }
}

